use eyre;
use color_eyre::Result;

struct BytecodeVM {
    memory: Vec<u8>,
}

impl BytecodeVM {
    fn new(bytecode: &[u8]) -> Self {
        BytecodeVM { memory: bytecode.to_vec() }
    }

    fn run(&self) -> Result<()> {
        println!("Starting VM execution...");
        let mut instruction_pointer = 0;

        loop {
            if instruction_pointer >= self.memory.len() {
                return Err(eyre::eyre!("Reached end of bytecode unexpectedly."));
            }

            match self.memory[instruction_pointer] {
                0x01 => {
                    println!("Executed LOAD instruction successfully.");
                    instruction_pointer += 1;
                },
                0xFF => {
                    return Err(eyre::eyre!("Fatal error: Unknown opcode encountered at position {}", instruction_pointer));
                }
                _ => {
                    println!("Skipping unknown byte.");
                    instruction_pointer += 1;
                }
            }
            if instruction_pointer < self.memory.len() {
                instruction_pointer += 1;
            } else {
                break;
            }
        }
        Ok(())
    }
}

fn main() -> Result<()> {
    let bytecode = vec![0x01, 0x02, 0xFF];
    let vm = BytecodeVM::new(&bytecode);

    match vm.run() {
        Ok(()) => println!("VM finished execution successfully."),
        Err(e) => eprintln!("Caught an error during VM run: {}", e), 
    }

    Ok(())
}

use eyre::eyre;
use color_eyre::Result;

struct DungeonGenerator {
    seed: u32,
}

impl DungeonGenerator {
    fn new(seed: u32) -> Self {
        DungeonGenerator { seed }
    }

    fn process_map_chunk(&self, chunk_data: Vec<i32>) -> Result<()> {
        if chunk_data.is_empty() {
            return Err(eyre::eyre!("Cannot process an empty map chunk."));
        }

        let sum: i32 = chunk_data.iter().sum();

        if sum < 0 {
             return Err(eyre::eyre!("Map data resulted in a negative total energy ({})", sum));
        }

        println!("Successfully processed chunk with sum: {}", sum);
        Ok(())
    }

    fn generate_dungeon(&self, chunks: Vec<Vec<i32>>) -> Result<()> {
        for (i, chunk) in chunks.into_iter().enumerate() {
            println!("nAttempting to process chunk {}...", i + 1);
            self.process_map_chunk(chunk)?;
        }
        Ok(())
    }
}

fn main() -> Result<()> {
    let generator = DungeonGenerator::new(42);

    let good_chunks = vec![
        vec![10, 5, 2],
        vec![1, 8]
    ];

    println!("--- Running test with valid data ---");
    match generator.generate_dungeon(good_chunks) {
        Ok(_) => println!("nDungeon generation completed successfully."),
        Err(e) => eprintln!("Caught expected error: {}", e),
    }

    let bad_chunk = vec![];
    let failing_chunks = vec![
        vec![10, 5],
        bad_chunk
    ];

    println!("n=============================");
    println!("--- Running test with empty data ---");
    match generator.generate_dungeon(failing_chunks) {
        Ok(_) => println!("Should not reach here."),
        Err(e) => eprintln!("Successfully caught error: {}", e),
    }

    Ok(())
}

use std::fs::File;
use std::io::{self, BufRead};
use std::net::SocketAddr;
use eyre::Result;

struct ConnectionAttempt {
    address: SocketAddr,
}

fn read_ips_from_file(filepath: &str) -> Result<Vec<ConnectionAttempt>> {
    let file = File::open(filepath)?;
    let reader = io::BufReader::new(file);
    let mut ips = Vec::new();

    for line in reader.lines() {
        let line = line?;
        if let Ok(addr) = line.trim().parse::<SocketAddr>() {
            ips.push(ConnectionAttempt { address: addr });
        }
    }
    Ok(ips)
}

fn check_connections(attempts: Vec<ConnectionAttempt>) -> Result<Vec<(SocketAddr, bool)>> {
    let mut results = Vec::new();
    for attempt in attempts {
        match std::net::TcpStream::connect_timeout(&attempt.address, std::time::Duration::from_secs(1)) {
            Ok(_) => results.push((attempt.address, true)),
            Err(_e) => results.push((attempt.address, false)),
        }
    }
    Ok(results)
}

fn main() -> Result<()> {
    let args: Vec<String> = std::env::args().collect();
    if args.len() != 2 {
        return Err(eyre::eyre!("Usage: {} <input_file>", args[0]));
    }
    let filepath = &args[1];

    let attempts = read_ips_from_file(filepath)?;
    if attempts.is_empty() {
        println!("No valid IP addresses found in the file.");
        return Ok(());
    }

    let results = check_connections(attempts)?;

    println!("n--- Connection Report ---n");
    for (addr, success) in results {
        if success {
            println!("[SUCCESS] Checked {}: Reachable.", addr);
        } else {
            println!("[FAILED]   Checked {}: Unreachable or timed out.", addr);
        }
    }

    Ok(())
}

use eyre::{eyre, Report};
use color_eyre::Result;

struct ApiRequest {
    endpoint: String,
    payload: String,
}

fn process_request(req: &ApiRequest) -> Result<String> {
    if req.endpoint.is_empty() {
        return Err(Report::from(std::io::Error::new(std::io::ErrorKind::InvalidInput, "Endpoint name cannot be blank")));
    }

    let processed = format!("Successfully handled request for endpoint: {}", req.endpoint);
    Ok(processed)
}

fn main() -> Result<()> {
    let good_request = ApiRequest {
        endpoint: "user/profile".to_string(),
        payload: r"{}".to_string(),
    };

    match process_request(&good_request) {
        Ok(result) => println!("Success: {}", result),
        Err(e) => eprintln!("Caught Error during good request simulation: {}", e),
    }

    let bad_request = ApiRequest {
        endpoint: String::new(),
        payload: r"{}".to_string(),
    };

    match process_request(&bad_request) {
        Ok(result) => println!("Success: {}", result),
        Err(e) => eprintln!("Caught Expected Error during bad request simulation: {}", e),
    }

    Ok(())
}

use eyre::eyre;
use color_eyre::Result;

struct DataValidator {
    name: String
}

impl DataValidator {
    fn new(name: &str) -> Self {
        DataValidator { name: name.to_string() }
    }

    fn validate(&self, data_list: &[&str]) -> Result<()> {
        if data_list.is_empty() {
            return Err(eyre::eyre!("The data list cannot be empty!"));
        }

        for item in data_list {
            if item.contains("bad_char") {
                return Err(eyre::eyre!("Found a problem with: {}. Please clean this up.", item));
            }
        }

        Ok(())
    }
}

fn main() -> Result<()> {
    let validator = DataValidator::new("Schema Checkpoint");

    let good_data = vec!["valid_record_1", "ok_item_2"];
    match validator.validate(&good_data) {
        Ok(()) => println!("Validation successful for {}", validator.name),
        Err(e) => eprintln!("Unexpected error on good data: {:#?}", e)
    }

    let bad_data = vec!["ok_item", "bad_char_record", "another_good_one"];
    match validator.validate(&bad_data) {
        Ok(()) => println!("Validation successful for {}", validator.name),
        Err(e) => eprintln!("Caught expected error: {:#?}", e)
    }

    let empty_data = vec![];
    match validator.validate(&empty_data) {
        Ok(()) => println!("Validation successful for {}", validator.name),
        Err(e) => eprintln!("Caught expected error: {:#?}", e)
    }

    Ok(())
}
